import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { CheckCircle, Cancel } from '@mui/icons-material';
import response from './response.json';

interface TodayHabit {
  habit: string;
  completed: boolean;
  streak: number;
}

interface WidgetData {
  todayHabits: TodayHabit[];
}

export default function Widget() {
  const { todayHabits } = response.data as WidgetData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 280, maxWidth: 380, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Typography variant="h6" fontWeight={600} sx={{ color: '#3B82F6' }}>
            Today's Habits
          </Typography>
          <Stack spacing={1}>
            {todayHabits.map((habit, index) => (
              <Box key={index} display="flex" justifyContent="space-between" alignItems="center">
                <Stack direction="row" alignItems="center" spacing={1}>
                  {habit.completed ? (
                    <CheckCircle sx={{ fontSize: 16, color: '#10B981' }} />
                  ) : (
                    <Cancel sx={{ fontSize: 16, color: '#EF4444' }} />
                  )}
                  <Typography variant="body2" sx={{ color: '#374151' }}>
                    {habit.habit}
                  </Typography>
                </Stack>
                <Chip
                  label={`Streak: ${habit.streak}`}
                  size="small"
                  sx={{ bgcolor: '#F3F4F6', fontSize: '11px' }}
                />
              </Box>
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
